function getBookTypeOptions(carrier) {
    if (carrier === "travelers") {
        return [
            {
                value: "auto",
                label: "Auto"
            },
            {
                value: "home",
                label: "Homeowners"
            },
            {
                value: "both",
                label: "Both"
            }
        ];
    }
    if (carrier === "hartford") {
        return [
            {
                value: "personal",
                label: "Personal Lines"
            },
            {
                value: "commercial",
                label: "Small Commercial"
            },
            {
                value: "both",
                label: "Both"
            }
        ];
    }
    if (carrier === "safeco") {
        return [
            {
                value: "auto",
                label: "Auto Only"
            },
            {
                value: "home",
                label: "Home Only"
            },
            {
                value: "both",
                label: "Auto + Home + Other"
            }
        ];
    }
    if (carrier === "berkshire") {
        return [
            {
                value: "commercial",
                label: "Commercial Lines"
            }
        ];
    }
    if (carrier === "libertymutual") {
        return [
            {
                value: "commercial",
                label: "Commercial Lines"
            }
        ];
    }
    // Progressive
    return [
        {
            value: "personal",
            label: "Personal Lines"
        },
        {
            value: "commercial",
            label: "Commercial Lines"
        },
        {
            value: "both",
            label: "Both"
        }
    ];
}
